// Code node — wrap trigger input into statusRecords
// Language: JavaScript
// Place between: Execute Workflow Trigger → this node → Airtable node

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const trigger = $input.first().json;

// The trigger output is the raw status record array
// Each item in $input is one status record
const allItems = $input.all();

// Build statusRecords array from all input items
const statusRecords = allItems.map(i => i.json);

log('Status records wrapped:', statusRecords.length);
log('First workstream:', statusRecords[0]?.workstream);

return [{
  json: {
    statusRecords: statusRecords
  }
}];

// Node 3 — assemble statusRecords + dependencyMap
// Language: JavaScript

// Read from the wrap node output, not the trigger directly

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const wrapNode = $('Code — wrap trigger input').first().json;

let statusRecords;
try {
  if (typeof wrapNode.statusRecords === 'string') {
    statusRecords = JSON.parse(wrapNode.statusRecords);
  } else if (Array.isArray(wrapNode.statusRecords)) {
    statusRecords = wrapNode.statusRecords;
  } else {
    throw new Error('statusRecords missing or wrong type');
  }
} catch(e) {
  throw new Error('Could not parse statusRecords: ' + e.message);
}

log('Status records received:', statusRecords.length);

// ── dependencyMap from Airtable ────────────────────────────
const airtableRows = $input.all();

log('Airtable rows fetched:', airtableRows.length);

if (airtableRows.length === 0) {
  throw new Error(
    'No dependency rows from Airtable. ' +
    'Check Base ID, table name, and that rows exist.'
  );
}

const dependencyMap = airtableRows
  .filter(i => i.json.fields?.Active !== false)
  .map(i => ({
    upstream:        i.json.fields['Upstream workstream']   ?? 'Unknown',
    downstream:      i.json.fields['Downstream Workstream'] ?? 'Unknown',
    lag_days:        i.json.fields['Lag Days']              ?? 0,
    dependency_type: i.json.fields.Type                 ?? 'blocks',
    notes:           i.json.fields.Notes                ?? ''
  }));

const dependencyCount = Object.keys(dependencyMap).length;

if (dependencyCount === 0) {
  warn(
    'No project dependencies found in Airtable for this run. ' +
    'Cross-workstream cascade risk analysis will be limited to single-workstream signals only. ' +
    'If dependencies are expected, check the Airtable Dependencies table and linked record fields.'
  );
} else {
  log('Dependency map built with', dependencyCount, 'entries.');
}

const dependencyContext = Object.keys(dependencyMap).length > 0
  ? JSON.stringify(dependencyMap, null, 2)
  : 'No dependency data available for this run. Analyse each workstream independently.';

return [{
  json: {
    statusRecords,
    dependencyMap,
    dependencyContext  // ← add this
  }
}];

