// Node 5 — parse OpenAI risk analysis response
// Language: JavaScript

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const response = $input.first().json;

// Surface API errors clearly
if (response.error) {
  throw new Error('OpenAI API error: ' + response.error.message);
}

// Guard missing choices
if (!response.choices || response.choices.length === 0) {
  throw new Error(
    'OpenAI returned no choices. Response: ' +
    JSON.stringify(response).slice(0, 300)
  );
}

const raw = response.choices[0].message.content;

if (!raw) {
  throw new Error('OpenAI message content is empty');
}

// Strip markdown fences
const clean = raw.replace(/```json|```/gi, '').trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('Invalid JSON from OpenAI: ' + raw.slice(0, 300));
}

// Schema validation
if (!parsed.risks || !Array.isArray(parsed.risks)) {
  throw new Error(
    'OpenAI response missing risks array.' +
    '\nRaw response: ' + raw.slice(0, 300)
  );
}

if (parsed.risks.length === 0) {
  warn('Risk Agent: OpenAI returned zero risks. Passing empty array downstream.');
}

const validSeverities = ['critical', 'amber', 'green'];
const riskFieldErrors = [];

parsed.risks.forEach((risk, i) => {
  const missingRiskFields = ['severity', 'description', 'owner'].filter(
    f => risk[f] === undefined || risk[f] === null || risk[f] === ''
  );
  if (missingRiskFields.length > 0) {
    riskFieldErrors.push(`Risk[${i}] missing: ${missingRiskFields.join(', ')}`);
  }
  if (risk.severity && !validSeverities.includes(risk.severity.toLowerCase())) {
    riskFieldErrors.push(`Risk[${i}] invalid severity: ${risk.severity}`);
  }
});

if (riskFieldErrors.length > 0) {
  throw new Error('Risk schema errors:\n' + riskFieldErrors.join('\n'));
}

// Validate required fields
if (!parsed.risks || !Array.isArray(parsed.risks)) {
  throw new Error('Response missing risks array: ' + raw.slice(0, 300));
}

log('Overall RAG:', parsed.overall_program_rag);
log('Total risks:', parsed.risks.length);
log('Critical risks:', parsed.risks.filter(r => r.severity === 'critical').length);

return [{ json: parsed }];

// Splits critical risks into separate items
// so Jira node creates one ticket per risk
// Language: JavaScript

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const criticalRisks = $json.risks.filter(r => r.severity === 'critical');

log('Creating Jira tickets for', criticalRisks.length, 'critical risks');

return criticalRisks.map(r => ({ json: r }));

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };

const riskSummary = $input.all().map(i => i.json);

log('Risk summary items being returned:', riskSummary.length);

return [{
  json: {
    riskSummary
  }
}];

const issueTypes = $input.first().json.issueTypes ?? [];
const risk = issueTypes.find(t => t.name.toLowerCase() === 'risk');

return [{
  json: {
    riskId: risk?.id ?? null
  }
}];
